"use strict";
var KEY="monAtelierCouture_v5";
var DEFAULT={
  profil:{mesures:{},styles:["bohème","naturel"]},
  palette:["#9c5d7c","#d9b8a3","#5b7152","#e8d9c0"],
  ai:{provider:"none",key:""},
  patImg:{},
  projets:[
    {id:1,name:"Jupe d'été en lin",piece:"Jupe",diff:"Facile",stat:"envie",tissu:"Lin moutarde, 1,5 m",date:""},
    {id:2,name:"Tote bag du marché",piece:"Sac",diff:"Facile",stat:"cours",tissu:"Toile coton écrue",date:""}
  ],
  inspirations:[],
  patrons:[],
  capsule:[
    {id:1,name:"Chemisier blanc",cat:"haut",color:"#f3efe7"},
    {id:2,name:"Jupe camel",cat:"bas",color:"#c79a6a"}
  ]
};
var state=load();
function load(){try{var r=localStorage.getItem(KEY);return r?Object.assign(JSON.parse(JSON.stringify(DEFAULT)),JSON.parse(r)):JSON.parse(JSON.stringify(DEFAULT));}catch(e){return JSON.parse(JSON.stringify(DEFAULT));}}
function save(){try{localStorage.setItem(KEY,JSON.stringify(state));return true;}catch(e){return false;}}
function uid(){return Date.now()+Math.floor(Math.random()*999);}
function toast(m){var t=$("toast");t.textContent=m;t.classList.add("show");clearTimeout(t._t);t._t=setTimeout(function(){t.classList.remove("show");},2300);}
function esc(s){return(s==null?"":String(s)).replace(/[&<>"]/g,function(c){return{"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;"}[c];});}
function jsq(s){return(s==null?"":String(s)).replace(/\\/g,"\\\\").replace(/'/g,"\\'");}
function $(id){return document.getElementById(id);}

function goView(v){document.querySelectorAll(".navbtn").forEach(function(n){n.classList.toggle("active",n.dataset.v===v);});document.querySelectorAll(".view").forEach(function(s){s.classList.toggle("active",s.id===v);});document.querySelectorAll("#stepper .s").forEach(function(s){s.classList.toggle("on",s.dataset.v===v);});window.scrollTo(0,0);}
document.querySelectorAll(".navbtn").forEach(function(b){b.addEventListener("click",function(){goView(b.dataset.v);});});
document.querySelectorAll("#stepper .s").forEach(function(b){b.addEventListener("click",function(){goView(b.dataset.v);});});

/* ===== CARNET ===== */
var carnetFilter="tous",carnetQuery="";
document.querySelectorAll("#carnetFilter button").forEach(function(b){b.addEventListener("click",function(){document.querySelectorAll("#carnetFilter button").forEach(function(n){n.classList.remove("on");});b.classList.add("on");carnetFilter=b.dataset.f;renderProjets();});});
$("carnetSearch").addEventListener("input",function(){carnetQuery=this.value.toLowerCase();renderProjets();});
var STAT={envie:"Envie",cours:"En cours",fini:"Terminé"};
function addProjet(){var name=$("pName").value.trim();if(!name){toast("Donne un nom au projet");return;}state.projets.unshift({id:uid(),name:name,piece:$("pPiece").value.trim(),diff:$("pDiff").value,stat:$("pStat").value,tissu:$("pTissu").value.trim(),date:$("pDate").value});save();["pName","pPiece","pTissu","pDate"].forEach(function(i){$(i).value="";});renderProjets();renderCarnetStats();toast("Projet ajouté au carnet");}
function delProjet(id){state.projets=state.projets.filter(function(p){return p.id!=id;});save();renderProjets();renderCarnetStats();}
function cycleStat(id){var o=["envie","cours","fini"];state.projets.forEach(function(p){if(p.id==id){p.stat=o[(o.indexOf(p.stat)+1)%3];}});save();renderProjets();renderCarnetStats();}
function renderCarnetStats(){var c={envie:0,cours:0,fini:0};state.projets.forEach(function(p){c[p.stat]++;});$("carnetStats").innerHTML=stat(c.envie,"Envies à coudre")+stat(c.cours,"En cours")+stat(c.fini,"Terminés");}
function stat(n,l){return '<div class="stat"><div class="n">'+n+'</div><div class="l">'+l+'</div></div>';}
function renderProjets(){var list=state.projets.filter(function(p){if(carnetFilter!="tous"&&p.stat!=carnetFilter)return false;if(carnetQuery){var h=((p.name||"")+" "+(p.piece||"")+" "+(p.tissu||"")).toLowerCase();if(h.indexOf(carnetQuery)<0)return false;}return true;});var el=$("projetList");if(!list.length){el.innerHTML='<div class="empty" style="grid-column:1/-1;">Aucun projet ici pour l\'instant.</div>';return;}el.innerHTML=list.map(function(p){return '<div class="card"><div style="display:flex;justify-content:space-between;align-items:flex-start;gap:8px;"><div><h3 style="font-size:16px;">'+esc(p.name)+'</h3><div class="muted" style="font-size:13px;margin-top:2px;">'+(p.piece?esc(p.piece):"")+(p.piece&&p.diff?" &middot; ":"")+(p.diff?'<span class="tag diff">'+esc(p.diff)+'</span>':"")+'</div></div><button class="x" title="Supprimer" onclick="delProjet('+p.id+')">&times;</button></div>'+(p.tissu?'<div style="font-size:13.5px;margin-top:10px;">&#9763; '+esc(p.tissu)+'</div>':'')+(p.date?'<div class="muted" style="font-size:13px;margin-top:4px;">&#9200; pour le '+esc(p.date)+'</div>':'')+'<div style="margin-top:14px;"><button class="pill '+p.stat+'" onclick="cycleStat('+p.id+')" style="border:none;cursor:pointer;">'+STAT[p.stat]+' &#8635;</button></div></div>';}).join("");}

/* ===== INSPIRATIONS ===== */
document.querySelectorAll("#inspoMode button").forEach(function(b){b.addEventListener("click",function(){document.querySelectorAll("#inspoMode button").forEach(function(n){n.classList.remove("on");});b.classList.add("on");var m=b.dataset.m;$("inspoLink").style.display=m=="link"?"block":"none";$("inspoImage").style.display=m=="image"?"block":"none";$("inspoManual").style.display=m=="manual"?"block":"none";});});
function platformOf(url){var u=(url||"").toLowerCase();if(u.indexOf("instagram.")>=0||u.indexOf("instagr.am")>=0)return "Instagram";if(u.indexOf("pinterest.")>=0||u.indexOf("pin.it")>=0)return "Pinterest";if(u.indexOf("vinted.")>=0)return "Vinted";return "Web";}
function fetchHtml(url){return fetch("https://api.allorigins.win/get?url="+encodeURIComponent(url)).then(function(r){if(!r.ok)throw 0;return r.json();}).then(function(d){return d.contents;}).catch(function(){return fetch("https://corsproxy.io/?url="+encodeURIComponent(url)).then(function(r){if(!r.ok)throw 0;return r.text();});});}
function metaFrom(html){var doc=new DOMParser().parseFromString(html,"text/html");function pick(sel){var e=doc.querySelector(sel);return e?(e.getAttribute("content")||e.getAttribute("href")||""):"";}return {img:pick('meta[property="og:image"]')||pick('meta[name="twitter:image"]')||pick('meta[property="og:image:url"]')||pick('link[rel="image_src"]'),title:pick('meta[property="og:title"]')||(doc.querySelector("title")?doc.querySelector("title").textContent:"")||"",desc:pick('meta[property="og:description"]')||pick('meta[name="description"]')||""};}
function importLink(){var url=$("impUrl").value.trim();var st=$("impStatus"),pv=$("impPreview");pv.innerHTML="";if(!url){toast("Colle un lien d'abord");return;}if(!/^https?:\/\//.test(url))url="https://"+url;var plat=platformOf(url);st.innerHTML='<span class="spin"></span> Recherche de l\'aperçu sur '+plat+'…';fetchHtml(url).then(function(html){var m=metaFrom(html);window._pending={img:m.img,url:url,platform:plat};st.innerHTML=m.img?'Aperçu trouvé sur <span class="badge '+plat+'">'+plat+'</span> — ajuste et épingle.':'Pas d\'image trouvée, mais tu peux enregistrer le lien.';pv.innerHTML='<div class="card" style="display:flex;gap:14px;flex-wrap:wrap;align-items:flex-start;">'+(m.img?'<img src="'+esc(m.img)+'" style="width:130px;height:130px;object-fit:cover;border-radius:10px;border:1px solid var(--line);" onerror="this.style.display=\'none\'">':'')+'<div style="flex:1;min-width:200px;"><label class="fld">Titre</label><input id="pvTitle" type="text" value="'+esc((m.title||"").slice(0,90))+'"><label class="fld" style="margin-top:8px;">Note</label><input id="pvNote" type="text" value="'+esc((m.desc||"").slice(0,120))+'" placeholder="Ce qui te plaît..."><button class="btn" style="margin-top:12px;" onclick="savePending()">Épingler</button></div></div>';}).catch(function(){window._pending={img:"",url:url,platform:plat};st.innerHTML='Récupération auto impossible. Tu peux quand même enregistrer le lien.';pv.innerHTML='<div class="card"><label class="fld">Titre</label><input id="pvTitle" type="text" placeholder="Mon inspiration '+plat+'"><button class="btn" style="margin-top:12px;" onclick="savePending()">Enregistrer le lien</button></div>';});}
function savePending(){var p=window._pending||{};var title=($("pvTitle")||{}).value||"Inspiration "+(p.platform||"");var note=($("pvNote")||{}).value||"";var obj={id:uid(),title:(title.trim()||("Inspiration "+(p.platform||""))),img:p.img||"",note:note.trim(),url:p.url||"",platform:p.platform||"Web",tags:[]};state.inspirations.unshift(obj);save();$("impUrl").value="";$("impStatus").innerHTML="";$("impPreview").innerHTML="";window._pending=null;renderInspo();refreshRefSelect();autoTag(obj);toast("Inspiration épinglée");}
function addInspoManual(){var t=$("iTitle").value.trim();if(!t){toast("Donne un titre");return;}var obj={id:uid(),title:t,img:$("iImg").value.trim(),note:$("iNote").value.trim(),url:"",platform:"Manuel",tags:[]};state.inspirations.unshift(obj);save();["iTitle","iImg","iNote"].forEach(function(i){$(i).value="";});renderInspo();autoTag(obj);toast("Inspiration épinglée");}
var dz=$("dropz");
dz.addEventListener("click",function(){$("imgFile").click();});
dz.addEventListener("dragover",function(e){e.preventDefault();dz.classList.add("drag");});
dz.addEventListener("dragleave",function(){dz.classList.remove("drag");});
dz.addEventListener("drop",function(e){e.preventDefault();dz.classList.remove("drag");handleImgFiles(e.dataTransfer.files);});
$("imgFile").addEventListener("change",function(){handleImgFiles(this.files);this.value="";});
function handleImgFiles(files){var arr=[].slice.call(files).filter(function(f){return f.type.indexOf("image")===0;});if(!arr.length)return;var done=0;arr.forEach(function(f){var rd=new FileReader();rd.onload=function(){var img=new Image();img.onload=function(){var max=760,w=img.width,h=img.height;if(w>max||h>max){var r=Math.min(max/w,max/h);w=Math.round(w*r);h=Math.round(h*r);}var cv=document.createElement("canvas");cv.width=w;cv.height=h;cv.getContext("2d").drawImage(img,0,0,w,h);var data=cv.toDataURL("image/jpeg",0.72);var obj={id:uid(),title:(f.name||"Image").replace(/\.[^.]+$/,""),img:data,note:"",url:"",platform:"Image",tags:[]};state.inspirations.unshift(obj);if(!save()){state.inspirations.shift();toast("Mémoire pleine — exporte/allège tes images");}else{autoTag(obj);}done++;if(done===arr.length){renderInspo();refreshRefSelect();toast(arr.length>1?arr.length+" images ajoutées":"Image ajoutée");}};img.src=rd.result;};rd.readAsDataURL(f);});}
function delInspo(id){state.inspirations=state.inspirations.filter(function(x){return x.id!=id;});save();renderInspo();refreshRefSelect();}
function inspoToProjet(id){var x=state.inspirations.filter(function(i){return i.id==id;})[0];if(!x)return;state.projets.unshift({id:uid(),name:x.title,piece:"",diff:"Facile",stat:"envie",tissu:x.note||"",date:""});save();renderProjets();renderCarnetStats();toast("Ajouté au carnet comme projet");}
/* tags */
var activeTags=[];
function allTags(){var s={};state.inspirations.forEach(function(x){(x.tags||[]).forEach(function(t){s[t]=(s[t]||0)+1;});});return Object.keys(s).sort(function(a,b){return s[b]-s[a];});}
function renderTagFilter(){var tags=allTags();var el=$("tagFilter");if(!tags.length){el.innerHTML="";return;}el.innerHTML='<span class="muted" style="font-size:12.5px;margin-right:6px;">Filtrer :</span>'+tags.map(function(t){return '<span class="tchip'+(activeTags.indexOf(t)<0?" off":"")+'" onclick="toggleTag(\''+jsq(t)+'\')">'+esc(t)+'</span>';}).join("")+(activeTags.length?' <span class="tchip" style="background:var(--surface2);color:var(--accent-ink);" onclick="clearTags()">&times; tout</span>':"");}
function toggleTag(t){var i=activeTags.indexOf(t);if(i<0)activeTags.push(t);else activeTags.splice(i,1);renderTagFilter();renderInspo();}
function clearTags(){activeTags=[];renderTagFilter();renderInspo();}
function editTags(id){var x=state.inspirations.filter(function(i){return i.id==id;})[0];if(!x)return;var v=prompt("Tags (séparés par des virgules) :",(x.tags||[]).join(", "));if(v===null)return;x.tags=v.split(",").map(function(s){return s.trim().toLowerCase();}).filter(function(s){return s;});save();renderInspo();renderTagFilter();}
function autoTag(x){var prov=(state.ai&&state.ai.provider)||"none";if(prov!=="none"&&state.ai.key&&x.img){visionTags(x.img).then(function(t){x.tags=t;save();renderInspo();renderTagFilter();}).catch(function(){x.tags=textTags(x);save();renderInspo();renderTagFilter();});}else{x.tags=textTags(x);save();renderTagFilter();}}
function tagInspo(id){var x=state.inspirations.filter(function(i){return i.id==id;})[0];if(!x)return;var prov=(state.ai&&state.ai.provider)||"none";if(prov!=="none"&&state.ai.key&&x.img){toast("Analyse de l'image…");visionTags(x.img).then(function(tags){x.tags=tags;save();renderInspo();renderTagFilter();toast("Tags ajoutés");}).catch(function(){x.tags=textTags(x);save();renderInspo();renderTagFilter();toast("Vision indispo — tags texte");});}else{x.tags=textTags(x);save();renderInspo();renderTagFilter();toast(prov==="none"?"Tags depuis le texte (ajoute une clé pour l'image)":"Pas d'image — tags texte");}}
function tagAllInspo(){var prov=(state.ai&&state.ai.provider)||"none";var imgs=state.inspirations.filter(function(x){return x.img&&(!x.tags||!x.tags.length);});if(prov==="none"||!state.ai.key){state.inspirations.forEach(function(x){if(!x.tags||!x.tags.length)x.tags=textTags(x);});save();renderInspo();renderTagFilter();toast("Tags depuis le texte (ajoute une clé pour les images)");return;}if(!imgs.length){toast("Rien à tagger");return;}toast("Analyse de "+imgs.length+" image(s)…");var i=0;function next(){if(i>=imgs.length){save();renderInspo();renderTagFilter();toast("Tagging terminé");return;}var x=imgs[i++];visionTags(x.img).then(function(t){x.tags=t;}).catch(function(){x.tags=textTags(x);}).then(function(){renderInspo();next();});}next();}
function textTags(x){var d=detect((x.title||"")+" "+(x.note||""));var t=[].concat(d.color,d.garment,d.detail,d.style);return t.filter(function(v,i){return t.indexOf(v)===i;}).slice(0,10);}
function visionTags(imgUrl){var prompt="Décris ce vêtement par 8 à 12 tags courts en français : couleur(s), type (robe, jupe, top, pantalon...), longueur, coupe/silhouette, encolure, manches, motif, style. Réponds UNIQUEMENT par les tags séparés par des virgules, en minuscules.";return callVision(prompt,imgUrl).then(function(txt){return txt.replace(/\n/g,",").split(",").map(function(s){return s.trim().toLowerCase().replace(/^[-•\d.\)]+\s*/,"");}).filter(function(s){return s&&s.length<28;}).filter(function(v,i,a){return a.indexOf(v)===i;}).slice(0,12);});}
function renderInspo(){var el=$("inspoList");$("inspoCount").textContent=state.inspirations.length?state.inspirations.length+" inspiration(s)":"";var list=state.inspirations.filter(function(x){if(!activeTags.length)return true;var tg=x.tags||[];return activeTags.every(function(t){return tg.indexOf(t)>=0;});});if(!list.length){el.innerHTML='<div class="empty" style="grid-column:1/-1;">'+(state.inspirations.length?"Aucune inspiration pour ces tags.":"Importe ta première inspiration : un lien Pinterest/Instagram/Vinted, ou une image.")+'</div>';return;}el.innerHTML=list.map(function(x){var ph=x.img?'<div class="ph" style="background-image:url(\''+(x.img.indexOf("data:")===0?x.img:esc(x.img))+'\')"></div>':'<div class="ph">&#10047; pas d\'image</div>';var src=x.url?'<a href="'+esc(x.url)+'" target="_blank" rel="noopener">source &#8599;</a>':'';var tags=(x.tags||[]).map(function(t){return '<span class="tchip" onclick="toggleTag(\''+jsq(t)+'\')">'+esc(t)+'</span>';}).join("");return '<div class="insp">'+ph+'<div class="bd"><div style="display:flex;justify-content:space-between;align-items:center;gap:6px;"><span class="badge '+(x.platform||"Manuel")+'">'+esc(x.platform||"Manuel")+'</span><button class="x" onclick="delInspo('+x.id+')">&times;</button></div><h4>'+esc(x.title)+'</h4>'+(x.note?'<div class="muted" style="font-size:13px;">'+esc(x.note)+'</div>':'')+(tags?'<div style="margin-top:8px;">'+tags+'</div>':'')+'<div style="margin-top:10px;display:flex;gap:8px;align-items:center;font-size:13px;flex-wrap:wrap;"><button class="btn ghost sm" onclick="tagInspo('+x.id+')">Tags IA</button><button class="btn ghost sm" onclick="editTags('+x.id+')">&#9998;</button><button class="btn ghost sm" onclick="inspoToProjet('+x.id+')">&#8594; projet</button>'+src+'</div></div></div>';}).join("");}
function renderPalette(){var el=$("paletteRow");el.innerHTML=state.palette.map(function(c,i){return '<div style="text-align:center;"><div class="swatch" style="background:'+c+'"></div><button class="x" style="font-size:13px;" onclick="delColor('+i+')">retirer</button></div>';}).join("")+'<label class="btn ghost sm" style="cursor:pointer;">+ couleur<input type="color" style="display:none;" onchange="addColor(this.value)"></label>';renderPaletteQuick();renderSketchPalette();}
function addColor(c){state.palette.push(c);save();renderPalette();}
function delColor(i){state.palette.splice(i,1);save();renderPalette();}

/* ===== IA ===== */
var LEX={style:["bohème","boho","minimaliste","vintage","rétro","romantique","casual","chic","sportif","streetwear","cottagecore","preppy","gothique","classique","moderne","élégant","oversize","ample","fluide","structuré","naturel","scandinave","parisien"],garment:{robe:"robe",robes:"robe",dress:"robe",jupe:"jupe",skirt:"jupe",top:"top",blouse:"blouse",chemise:"chemise",shirt:"chemise",pantalon:"pantalon",pants:"pantalon",jean:"jean",short:"short",veste:"veste",jacket:"veste",manteau:"manteau",coat:"manteau",combinaison:"combinaison",pull:"pull","t-shirt":"t-shirt",tshirt:"t-shirt",gilet:"gilet",cardigan:"cardigan"},fabric:["lin","coton","laine","soie","velours","jean","denim","viscose","satin","crêpe","jersey","maille","tweed","gaze","mousseline","cuir","liberty","popeline"],detail:["manches ballon","manches longues","sans manche","col v","col claudine","encolure","fronces","plis","volants","boutons","ceinture","poches","taille haute","dos nu","smocks","broderie","asymétrique","portefeuille"],color:["beige","écru","blanc","noir","bleu","marine","vert","kaki","rouge","bordeaux","rose","moutarde","jaune","ocre","terracotta","camel","gris","violet","corail","pastel"]};
function detect(text){var c=(text||corpus()).toLowerCase();var res={style:[],garment:[],fabric:[],detail:[],color:[]};LEX.style.forEach(function(w){if(c.indexOf(w)>=0&&res.style.indexOf(w)<0)res.style.push(w);});Object.keys(LEX.garment).forEach(function(w){if(c.indexOf(w)>=0){var g=LEX.garment[w];if(res.garment.indexOf(g)<0)res.garment.push(g);}});LEX.fabric.forEach(function(w){if(c.indexOf(w)>=0&&res.fabric.indexOf(w)<0)res.fabric.push(w);});LEX.detail.forEach(function(w){if(c.indexOf(w)>=0&&res.detail.indexOf(w)<0)res.detail.push(w);});LEX.color.forEach(function(w){if(c.indexOf(w)>=0&&res.color.indexOf(w)<0)res.color.push(w);});return res;}
function corpus(){var t=[];state.inspirations.forEach(function(x){t.push((x.title||"")+" "+(x.note||"")+" "+((x.tags||[]).join(" ")));});(state.profil.styles||[]).forEach(function(s){t.push(s);});return t.join(" ").toLowerCase();}
function heuristicReport(){var d=detect(),n=state.inspirations.length;if(!n&&!(state.profil.styles||[]).length){return '<div class="empty">Ajoute d\'abord quelques inspirations (onglet 1), puis reviens ici.</div>';}var styles=d.style.length?d.style.slice(0,5):(state.profil.styles||["à préciser"]);var garments=d.garment.length?d.garment:["robe","jupe","top"];var fabrics=d.fabric.length?d.fabric:["lin","coton"];var details=d.detail.length?d.detail:["fronces","manches courtes"];function pick(a,i){return a[i%a.length];}var ideas=[];for(var i=0;i<3;i++){ideas.push((i+1)+". Une "+pick(garments,i)+" "+pick(styles,i)+" en "+pick(fabrics,i)+", avec "+pick(details,i)+".");}var sw=state.palette.map(function(c){return '<span class="swatch" style="display:inline-block;width:24px;height:24px;background:'+c+';vertical-align:middle;margin-right:5px;"></span>';}).join("");var html='<div class="card" style="background:var(--accent-soft);border:none;margin-bottom:16px;"><div style="font-size:13px;color:var(--accent-ink);font-weight:600;letter-spacing:.4px;text-transform:uppercase;">Ton profil de style</div><div style="font-size:19px;font-weight:600;margin-top:4px;color:var(--accent-ink);">'+styles.slice(0,4).join(" &middot; ")+'</div><div class="muted" style="font-size:13px;margin-top:4px;">d\'après '+n+' inspiration(s)</div></div>';html+='<div class="ai-out">';html+="Vêtements qui reviennent : "+garments.join(", ")+".\n";if(d.fabric.length)html+="Matières évoquées : "+fabrics.join(", ")+".\n";if(d.detail.length)html+="Détails repérés : "+details.join(", ")+".\n";html+="\nPalette : "+sw+"\n\n";html+="3 pistes à dessiner :\n"+ideas.join("\n");html+="\n\nProchaine étape : ouvre le Studio pour mettre en forme la première idée.";html+='</div>';html+='<div style="margin-top:14px;display:flex;gap:8px;flex-wrap:wrap;"><button class="btn sm" onclick="goView(\'studio\')">Ouvrir le Studio</button><button class="btn ghost sm" onclick="goView(\'patrons\')">Voir des patrons</button></div>';return html;}
function saveAiKey(){state.ai={provider:$("aiProvider").value,key:$("aiKey").value.trim()};save();toast(state.ai.provider==="none"?"Mode local activé":"Clé enregistrée (sur cet appareil)");updateAiMode();}
function updateAiMode(){var p=(state.ai&&state.ai.provider)||"none";$("aiMode").textContent=p==="none"?"Mode : analyse locale":"Mode : IA "+p;if($("aiProvider"))$("aiProvider").value=p;if($("aiKey"))$("aiKey").value=(state.ai&&state.ai.key)||"";}
function runAssistant(){var out=$("aiResult");var p=(state.ai&&state.ai.provider)||"none";if(p==="none"||!(state.ai&&state.ai.key)){out.innerHTML=heuristicReport();return;}out.innerHTML='<div class="muted"><span class="spin"></span> L\'IA réfléchit à tes inspirations…</div>';var pr="Tu es styliste. Voici les inspirations couture (titres/notes/tags) et mots-clés de style :\n"+corpus().slice(0,1500)+"\n\nEn français, concis : 1) profil de style en 3-4 mots-clés, 2) vêtements et matières récurrents, 3) trois idées de créations précises (vêtement + coupe + tissu + détail). Format clair.";callText(pr).then(function(txt){out.innerHTML=heuristicReport()+'<div class="card" style="margin-top:16px;"><div style="font-size:13px;color:var(--accent-ink);font-weight:600;text-transform:uppercase;letter-spacing:.4px;margin-bottom:8px;">Idées rédigées par l\'IA</div><div class="ai-out">'+esc(txt)+'</div></div>';}).catch(function(err){out.innerHTML=heuristicReport()+'<div class="muted" style="margin-top:14px;font-size:13px;">Appel IA échoué ('+esc(String(err).slice(0,80))+'). Analyse locale ci-dessus.</div>';});}
function callText(prompt){var prov=state.ai.provider,key=state.ai.key;if(prov==="openai")return fetch("https://api.openai.com/v1/chat/completions",{method:"POST",headers:{"Content-Type":"application/json","Authorization":"Bearer "+key},body:JSON.stringify({model:"gpt-4o-mini",messages:[{role:"user",content:prompt}],max_tokens:600})}).then(function(r){return r.json();}).then(function(d){if(d.error)throw d.error.message;return d.choices[0].message.content;});if(prov==="anthropic")return fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json","x-api-key":key,"anthropic-version":"2023-06-01","anthropic-dangerous-direct-browser-access":"true"},body:JSON.stringify({model:"claude-3-5-haiku-latest",max_tokens:600,messages:[{role:"user",content:prompt}]})}).then(function(r){return r.json();}).then(function(d){if(d.error)throw d.error.message;return d.content[0].text;});return Promise.reject("fournisseur");}
function callVision(prompt,imgUrl){var prov=state.ai.provider,key=state.ai.key;if(prov==="openai")return fetch("https://api.openai.com/v1/chat/completions",{method:"POST",headers:{"Content-Type":"application/json","Authorization":"Bearer "+key},body:JSON.stringify({model:"gpt-4o-mini",max_tokens:200,messages:[{role:"user",content:[{type:"text",text:prompt},{type:"image_url",image_url:{url:imgUrl}}]}]})}).then(function(r){return r.json();}).then(function(d){if(d.error)throw d.error.message;return d.choices[0].message.content;});if(prov==="anthropic"){var srcObj;var mm=imgUrl.match(/^data:(.*?);base64,(.*)$/);if(mm)srcObj={type:"base64",media_type:mm[1],data:mm[2]};else srcObj={type:"url",url:imgUrl};return fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json","x-api-key":key,"anthropic-version":"2023-06-01","anthropic-dangerous-direct-browser-access":"true"},body:JSON.stringify({model:"claude-3-5-haiku-latest",max_tokens:200,messages:[{role:"user",content:[{type:"image",source:srcObj},{type:"text",text:prompt}]}]})}).then(function(r){return r.json();}).then(function(d){if(d.error)throw d.error.message;return d.content[0].text;});}return Promise.reject("fournisseur");}

