var design={type:"robe",sil:"droite",len:"genou",neck:"ras",sleeve:"courte",hem:"simple",waist:"aucun",poches:false,boutons:false,fente:false,print:"uni",color:"#9c5d7c",view:"devant"};
document.querySelectorAll("#studioMode button").forEach(function(b){b.addEventListener("click",function(){document.querySelectorAll("#studioMode button").forEach(function(n){n.classList.remove("on");});b.classList.add("on");var s=b.dataset.s;$("studioCompose").style.display=s=="compose"?"block":"none";$("studioDraw").style.display=s=="draw"?"block":"none";if(s=="draw")initSketch();});});
function renderPaletteQuick(){var el=$("dPaletteQuick");if(!el)return;el.innerHTML=state.palette.map(function(c){return '<button class="swatch" style="width:26px;height:26px;background:'+c+';cursor:pointer;" title="utiliser" onclick="setDesignColor(\''+c+'\')"></button>';}).join("");}
