document.querySelectorAll("#dType button").forEach(function(b){b.addEventListener("click",function(){document.querySelectorAll("#dType button").forEach(function(n){n.classList.remove("on");});b.classList.add("on");design.type=b.dataset.t;var topish=(design.type=="robe"||design.type=="top");$("dNeckWrap").style.display=topish?"block":"none";$("dSleeveWrap").style.display=topish?"block":"none";drawDesign();});});
document.querySelectorAll("#dPrint button").forEach(function(b){b.addEventListener("click",function(){document.querySelectorAll("#dPrint button").forEach(function(n){n.classList.remove("on");});b.classList.add("on");design.print=b.dataset.p;drawDesign();});});
document.querySelectorAll("#dViewSeg button").forEach(function(b){b.addEventListener("click",function(){document.querySelectorAll("#dViewSeg button").forEach(function(n){n.classList.remove("on");});b.classList.add("on");design.view=b.dataset.w;drawDesign();});});
["dSil","dLen","dNeck","dSleeve","dHem","dWaist"].forEach(function(id){var e=$(id);if(e)e.addEventListener("change",readDesign);});
["dPoches","dBoutons","dFente"].forEach(function(id){var e=$(id);if(e)e.addEventListener("change",readDesign);});
$("dColor").addEventListener("input",function(){design.color=this.value;drawDesign();});
function readDesign(){design.sil=$("dSil").value;design.len=$("dLen").value;design.neck=$("dNeck").value;design.sleeve=$("dSleeve").value;design.hem=$("dHem").value;design.waist=$("dWaist").value;design.poches=$("dPoches").checked;design.boutons=$("dBoutons").checked;design.fente=$("dFente").checked;drawDesign();}
function printDefs(print,color){if(print=="uni")return {fill:color,defs:""};var d="";if(print=="pois")d='<pattern id="pat" width="20" height="20" patternUnits="userSpaceOnUse"><rect width="20" height="20" fill="'+color+'"/><circle cx="5" cy="5" r="2.4" fill="#ffffff" fill-opacity="0.65"/><circle cx="15" cy="15" r="2.4" fill="#ffffff" fill-opacity="0.65"/></pattern>';else if(print=="rayures")d='<pattern id="pat" width="16" height="10" patternUnits="userSpaceOnUse"><rect width="16" height="10" fill="'+color+'"/><rect width="8" height="10" fill="#ffffff" fill-opacity="0.35"/></pattern>';else d='<pattern id="pat" width="26" height="26" patternUnits="userSpaceOnUse"><rect width="26" height="26" fill="'+color+'"/><g fill="#ffffff" fill-opacity="0.6"><circle cx="8" cy="8" r="2"/><circle cx="12" cy="6" r="2"/><circle cx="10" cy="11" r="2"/><circle cx="20" cy="19" r="2"/><circle cx="24" cy="17" r="2"/><circle cx="22" cy="22" r="2"/></g></pattern>';return {fill:"url(#pat)",defs:d};}
function detailOverlays(C,waistY,hemY,halfW,halfH,applyHem){
  var st="#5a4a52",o="";
  if(design.waist=="ceinture")o+='<rect x="'+(C-halfW)+'" y="'+(waistY-5)+'" width="'+(halfW*2)+'" height="10" fill="rgba(90,74,82,0.5)" stroke="'+st+'" stroke-width="1.4"/>';
  else if(design.waist=="noeud")o+='<path d="M '+C+' '+waistY+' l -16 -8 l 0 16 z" fill="rgba(90,74,82,0.55)" stroke="'+st+'" stroke-width="1.2"/><path d="M '+C+' '+waistY+' l 16 -8 l 0 16 z" fill="rgba(90,74,82,0.55)" stroke="'+st+'" stroke-width="1.2"/><rect x="'+(C-3)+'" y="'+(waistY-4)+'" width="6" height="8" fill="'+st+'"/>';
  if(design.boutons){o+='<line x1="'+C+'" y1="'+(waistY-44)+'" x2="'+C+'" y2="'+(hemY-12)+'" stroke="'+st+'" stroke-width="1" stroke-dasharray="2 3"/>';for(var by=waistY-36;by<hemY-12;by+=20)o+='<circle cx="'+C+'" cy="'+by+'" r="2" fill="'+st+'"/>';}
  if(design.poches){var py=waistY+18;o+='<rect x="'+(C-halfW*0.5-20)+'" y="'+py+'" width="20" height="22" rx="3" fill="none" stroke="'+st+'" stroke-width="1.4"/><rect x="'+(C+halfW*0.5)+'" y="'+py+'" width="20" height="22" rx="3" fill="none" stroke="'+st+'" stroke-width="1.4"/>';}
  if(design.fente)o+='<line x1="'+C+'" y1="'+(hemY-48)+'" x2="'+C+'" y2="'+(hemY-2)+'" stroke="'+st+'" stroke-width="2"/>';
  if(applyHem){
    if(design.hem=="volante"){o+='<path d="M '+(C-halfH)+' '+(hemY-14)+' ';for(var x=C-halfH;x<C+halfH;x+=18){o+='q 9 12 18 0 ';}o+='" fill="none" stroke="'+st+'" stroke-width="1.4" opacity="0.8"/>';}
    else if(design.hem=="plisse"){for(var px=C-halfH+12;px<C+halfH-8;px+=15)o+='<line x1="'+px+'" y1="'+(hemY-80)+'" x2="'+px+'" y2="'+(hemY-4)+'" stroke="'+st+'" stroke-width="1" opacity="0.45"/>';}
    else if(design.hem=="asymetrique")o+='<line x1="'+(C-halfH)+'" y1="'+(hemY-34)+'" x2="'+(C+halfH)+'" y2="'+(hemY+20)+'" stroke="'+st+'" stroke-width="2"/>';
    else if(design.hem=="portefeuille")o+='<line x1="'+(C-halfH*0.2)+'" y1="'+waistY+'" x2="'+(C+halfH*0.7)+'" y2="'+(hemY-4)+'" stroke="'+st+'" stroke-width="1.6" stroke-dasharray="5 3"/>';
  }
  return o;
}
function drawDesign(){
  var svg=$("designSvg");var C=150;var pf=printDefs(design.print,design.color);var stroke="#5a4a52";var parts="";var lenMap={mini:0,genou:1,midi:2,long:3};var topish=(design.type=="robe"||design.type=="top");var dos=(design.view=="dos");
  function poly(pts){return "M"+pts.map(function(p){return p[0].toFixed(1)+" "+p[1].toFixed(1);}).join(" L ")+" Z";}
  if(topish){
    var shoulderY=92,bustY=150,waistY=205,hipY=240,shoulderHalf=58,bustHalf=50;
    var waistHalf=design.sil=="ajustee"?38:(design.sil=="ample"?60:48);
    var hipHalf=design.sil=="ajustee"?52:(design.sil=="ample"?64:54);
    var hemY,hemHalf;if(design.type=="top"){hemY=[185,225,255,280][lenMap[design.len]];}else{hemY=[300,355,400,448][lenMap[design.len]];}
    if(design.sil=="droite")hemHalf=waistHalf+4;else if(design.sil=="evasee")hemHalf=(design.type=="top"?bustHalf+30:waistHalf+58);else if(design.sil=="ajustee")hemHalf=hipHalf-2;else hemHalf=72;
    var neckHalf,neckPath,nk=dos?"rasdos":design.neck;
    if(nk=="ras"){neckHalf=18;neckPath="Q "+C+" "+(shoulderY+16)+" "+(C-neckHalf)+" "+shoulderY;}
    else if(nk=="rasdos"){neckHalf=18;neckPath="Q "+C+" "+(shoulderY+7)+" "+(C-neckHalf)+" "+shoulderY;}
    else if(nk=="v"){neckHalf=18;neckPath="L "+C+" "+(shoulderY+46)+" L "+(C-neckHalf)+" "+shoulderY;}
    else if(nk=="bateau"){neckHalf=32;neckPath="Q "+C+" "+(shoulderY+8)+" "+(C-neckHalf)+" "+shoulderY;}
    else {neckHalf=22;neckPath="L "+(C-neckHalf)+" "+(shoulderY+26)+" L "+(C+neckHalf)+" "+(shoulderY+26)+" L "+(C+neckHalf)+" "+shoulderY;}
    var carre=(nk=="carre");var body=[];
    body.push([C-shoulderHalf,shoulderY]);body.push([C-bustHalf,bustY]);body.push([C-waistHalf,waistY]);if(design.type!="top")body.push([C-hipHalf,hipY]);body.push([C-hemHalf,hemY]);body.push([C+hemHalf,hemY]);if(design.type!="top")body.push([C+hipHalf,hipY]);body.push([C+waistHalf,waistY]);body.push([C+bustHalf,bustY]);body.push([C+shoulderHalf,shoulderY]);
    var bodyPath;
    if(carre){bodyPath="M "+(C-shoulderHalf)+" "+shoulderY+" L "+(C-bustHalf)+" "+bustY+" L "+(C-waistHalf)+" "+waistY+(design.type!="top"?" L "+(C-hipHalf)+" "+hipY:"")+" L "+(C-hemHalf)+" "+hemY+" L "+(C+hemHalf)+" "+hemY+(design.type!="top"?" L "+(C+hipHalf)+" "+hipY:"")+" L "+(C+waistHalf)+" "+waistY+" L "+(C+bustHalf)+" "+bustY+" L "+(C+shoulderHalf)+" "+shoulderY+" L "+(C+neckHalf)+" "+shoulderY+" L "+(C+neckHalf)+" "+(shoulderY+26)+" L "+(C-neckHalf)+" "+(shoulderY+26)+" L "+(C-neckHalf)+" "+shoulderY+" Z";}
    else { bodyPath=poly(body).slice(0,-2)+" L "+(C+neckHalf)+" "+shoulderY+" "+neckPath+" Z"; }
    var sl="";
    if(design.sleeve!="sans"){
      if(design.sleeve=="courte"||design.sleeve=="flutter"){var ext=design.sleeve=="flutter"?34:26,dy=design.sleeve=="flutter"?22:10;sl+='<path d="M '+(C-shoulderHalf)+' '+shoulderY+' L '+(C-shoulderHalf-ext)+' '+(shoulderY+dy)+' L '+(C-shoulderHalf-ext+6)+' '+(bustY-6)+' L '+(C-bustHalf)+' '+bustY+' Z" fill="'+pf.fill+'" stroke="'+stroke+'" stroke-width="2"/>';sl+='<path d="M '+(C+shoulderHalf)+' '+shoulderY+' L '+(C+shoulderHalf+ext)+' '+(shoulderY+dy)+' L '+(C+shoulderHalf+ext-6)+' '+(bustY-6)+' L '+(C+bustHalf)+' '+bustY+' Z" fill="'+pf.fill+'" stroke="'+stroke+'" stroke-width="2"/>';if(design.sleeve=="flutter"){sl+='<path d="M '+(C-shoulderHalf-ext)+' '+(shoulderY+dy)+' q 6 10 '+(ext-6)+' '+(bustY-6-shoulderY-dy)+'" fill="none" stroke="'+stroke+'" stroke-width="1" opacity="0.5"/>';}}
      else if(design.sleeve=="longue"){sl+='<path d="M '+(C-shoulderHalf)+' '+shoulderY+' L '+(C-shoulderHalf-24)+' '+(shoulderY+8)+' L '+(C-shoulderHalf-14)+' 250 L '+(C-shoulderHalf+4)+' 250 L '+(C-bustHalf)+' '+bustY+' Z" fill="'+pf.fill+'" stroke="'+stroke+'" stroke-width="2"/>';sl+='<path d="M '+(C+shoulderHalf)+' '+shoulderY+' L '+(C+shoulderHalf+24)+' '+(shoulderY+8)+' L '+(C+shoulderHalf+14)+' 250 L '+(C+shoulderHalf-4)+' 250 L '+(C+bustHalf)+' '+bustY+' Z" fill="'+pf.fill+'" stroke="'+stroke+'" stroke-width="2"/>';}
      else if(design.sleeve=="bishop"){sl+='<path d="M '+(C-shoulderHalf)+' '+shoulderY+' C '+(C-shoulderHalf-46)+' '+(shoulderY+40)+' '+(C-shoulderHalf-40)+' 230 '+(C-shoulderHalf-2)+' 252 L '+(C-shoulderHalf+12)+' 250 L '+(C-bustHalf)+' '+bustY+' Z" fill="'+pf.fill+'" stroke="'+stroke+'" stroke-width="2"/>';sl+='<path d="M '+(C+shoulderHalf)+' '+shoulderY+' C '+(C+shoulderHalf+46)+' '+(shoulderY+40)+' '+(C+shoulderHalf+40)+' 230 '+(C+shoulderHalf+2)+' 252 L '+(C+shoulderHalf-12)+' 250 L '+(C+bustHalf)+' '+bustY+' Z" fill="'+pf.fill+'" stroke="'+stroke+'" stroke-width="2"/>';}
      else {sl+='<path d="M '+(C-shoulderHalf)+' '+shoulderY+' C '+(C-shoulderHalf-40)+' '+(shoulderY+6)+' '+(C-shoulderHalf-40)+' '+(bustY-2)+' '+(C-bustHalf-6)+' '+(bustY+6)+' L '+(C-bustHalf)+' '+bustY+' Z" fill="'+pf.fill+'" stroke="'+stroke+'" stroke-width="2"/>';sl+='<path d="M '+(C+shoulderHalf)+' '+shoulderY+' C '+(C+shoulderHalf+40)+' '+(shoulderY+6)+' '+(C+shoulderHalf+40)+' '+(bustY-2)+' '+(C+bustHalf+6)+' '+(bustY+6)+' L '+(C+bustHalf)+' '+bustY+' Z" fill="'+pf.fill+'" stroke="'+stroke+'" stroke-width="2"/>';}
    }
    parts=sl+'<path d="'+bodyPath+'" fill="'+pf.fill+'" stroke="'+stroke+'" stroke-width="2.2" stroke-linejoin="round"/>';
    if(dos){parts+='<line x1="'+C+'" y1="'+(shoulderY+6)+'" x2="'+C+'" y2="'+(hemY-6)+'" stroke="'+stroke+'" stroke-width="1.2" stroke-dasharray="2 3" opacity="0.6"/><circle cx="'+C+'" cy="'+(shoulderY+14)+'" r="2.4" fill="none" stroke="'+stroke+'" stroke-width="1.2"/>';}
    else{parts+='<line x1="'+C+'" y1="'+(shoulderY+28)+'" x2="'+C+'" y2="'+(hemY-6)+'" stroke="'+stroke+'" stroke-width="1" stroke-dasharray="3 4" opacity="0.45"/>';}
    parts+='<line x1="'+(C-hemHalf+4)+'" y1="'+(hemY-5)+'" x2="'+(C+hemHalf-4)+'" y2="'+(hemY-5)+'" stroke="'+stroke+'" stroke-width="1" stroke-dasharray="2 3" opacity="0.5"/>';
    parts+=detailOverlays(C,waistY,hemY,waistHalf,hemHalf,true);
  } else if(design.type=="jupe"){
    var wY=150,hemY2=[235,300,360,440][lenMap[design.len]];var wHalf=design.sil=="ample"?60:48,hemHalf2;
    if(design.sil=="droite")hemHalf2=wHalf+2;else if(design.sil=="evasee")hemHalf2=wHalf+62;else if(design.sil=="ajustee")hemHalf2=wHalf+10;else hemHalf2=82;
    parts='<rect x="'+(C-wHalf)+'" y="'+(wY-16)+'" width="'+(wHalf*2)+'" height="16" rx="3" fill="'+design.color+'" stroke="'+stroke+'" stroke-width="2"/>';
    parts+='<path d="M '+(C-wHalf)+' '+wY+' L '+(C-hemHalf2)+' '+hemY2+' L '+(C+hemHalf2)+' '+hemY2+' L '+(C+wHalf)+' '+wY+' Z" fill="'+pf.fill+'" stroke="'+stroke+'" stroke-width="2.2" stroke-linejoin="round"/>';
    if(dos)parts+='<line x1="'+C+'" y1="'+(wY-16)+'" x2="'+C+'" y2="'+(hemY2-6)+'" stroke="'+stroke+'" stroke-width="1.2" stroke-dasharray="2 3" opacity="0.6"/>';
    parts+='<line x1="'+(C-hemHalf2+4)+'" y1="'+(hemY2-5)+'" x2="'+(C+hemHalf2-4)+'" y2="'+(hemY2-5)+'" stroke="'+stroke+'" stroke-width="1" stroke-dasharray="2 3" opacity="0.5"/>';
    parts+=detailOverlays(C,wY,hemY2,wHalf,hemHalf2,true);
  } else {
    var wY3=150,ankleY=[250,330,390,448][lenMap[design.len]];var wHalf3=design.sil=="ample"?58:46;var legBot=design.sil=="ample"?40:(design.sil=="ajustee"?18:28);var crotchY=205,gap=6,legTop=wHalf3-8;
    parts='<rect x="'+(C-wHalf3)+'" y="'+(wY3-16)+'" width="'+(wHalf3*2)+'" height="16" rx="3" fill="'+design.color+'" stroke="'+stroke+'" stroke-width="2"/>';
    parts+='<path d="M '+(C-wHalf3)+' '+wY3+' L '+(C-legBot)+' '+ankleY+' L '+(C-gap)+' '+ankleY+' L '+(C-gap)+' '+crotchY+' L '+(C-legTop)+' '+wY3+' Z" fill="'+pf.fill+'" stroke="'+stroke+'" stroke-width="2.2" stroke-linejoin="round"/>';
    parts+='<path d="M '+(C+wHalf3)+' '+wY3+' L '+(C+legBot)+' '+ankleY+' L '+(C+gap)+' '+ankleY+' L '+(C+gap)+' '+crotchY+' L '+(C+legTop)+' '+wY3+' Z" fill="'+pf.fill+'" stroke="'+stroke+'" stroke-width="2.2" stroke-linejoin="round"/>';
    parts+=detailOverlays(C,wY3,ankleY,wHalf3,wHalf3,false);
  }
  svg.innerHTML='<defs>'+pf.defs+'</defs>'+parts;
  var T={robe:"Robe",jupe:"Jupe",top:"Top",pantalon:"Pantalon"},S={droite:"droite",evasee:"évasée",ajustee:"ajustée",ample:"ample"},L={mini:"courte",genou:"aux genoux",midi:"midi",long:"longue"};
  var sum=T[design.type]+" "+S[design.sil]+", longueur "+L[design.len];if(topish)sum+=", encolure "+$("dNeck").options[$("dNeck").selectedIndex].text.toLowerCase()+", manches "+$("dSleeve").options[$("dSleeve").selectedIndex].text.toLowerCase();var extra=[];if(design.hem&&design.hem!="simple")extra.push("bas "+design.hem);if(design.waist&&design.waist!="aucun")extra.push(design.waist);if(design.poches)extra.push("poches");if(design.boutons)extra.push("boutons");if(design.fente)extra.push("fente");sum+=(extra.length?", "+extra.join(", "):"")+", imprimé "+design.print+" ("+design.view+").";$("designSummary").textContent=sum;window._designSummary=sum;
}
