var sk={ctx:null,draw:false,eraser:false,undo:[],lx:0,ly:0,init:false};
function initSketch(){if(sk.init){renderSketchPalette();return;}var cv=$("sketchCanvas");sk.ctx=cv.getContext("2d");sk.ctx.lineCap="round";sk.ctx.lineJoin="round";sketchClear(true);
  function pos(e){var r=cv.getBoundingClientRect();var cx=(e.touches?e.touches[0].clientX:e.clientX)-r.left;var cy=(e.touches?e.touches[0].clientY:e.clientY)-r.top;return {x:cx*(cv.width/r.width),y:cy*(cv.height/r.height)};}
  function down(e){e.preventDefault();pushUndo();sk.draw=true;var p=pos(e);sk.lx=p.x;sk.ly=p.y;}
  function move(e){if(!sk.draw)return;e.preventDefault();var p=pos(e);var c=sk.ctx;c.strokeStyle=sk.eraser?"#ffffff":$("brushColor").value;c.lineWidth=parseFloat($("brushSize").value)*(cv.width/(cv.getBoundingClientRect().width||cv.width));c.beginPath();c.moveTo(sk.lx,sk.ly);c.lineTo(p.x,p.y);c.stroke();sk.lx=p.x;sk.ly=p.y;}
  function up(){sk.draw=false;}
  cv.addEventListener("mousedown",down);cv.addEventListener("mousemove",move);window.addEventListener("mouseup",up);cv.addEventListener("touchstart",down,{passive:false});cv.addEventListener("touchmove",move,{passive:false});cv.addEventListener("touchend",up);
  $("brushSize").addEventListener("input",function(){$("brushOut").textContent=this.value;});
  $("eraserBtn").addEventListener("click",function(){sk.eraser=!sk.eraser;this.classList.toggle("on");this.textContent=sk.eraser?"Pinceau":"Gomme";});
  $("refSelect").addEventListener("change",loadRef);
  sk.init=true;renderSketchPalette();refreshRefSelect();}
function renderSketchPalette(){var el=$("sketchPalette");if(!el)return;el.innerHTML=state.palette.map(function(c){return '<button class="swatch" style="width:24px;height:24px;background:'+c+';cursor:pointer;" title="couleur" onclick="document.getElementById(\'brushColor\').value=\''+c+'\';"></button>';}).join("");}
function pushUndo(){try{sk.undo.push($("sketchCanvas").toDataURL("image/png"));if(sk.undo.length>15)sk.undo.shift();}catch(e){}}
function sketchUndo(){if(!sk.undo.length)return;var d=sk.undo.pop();var img=new Image();img.onload=function(){var cv=$("sketchCanvas");sk.ctx.clearRect(0,0,cv.width,cv.height);sk.ctx.drawImage(img,0,0);};img.src=d;}
function sketchClear(silent){var cv=$("sketchCanvas");sk.ctx.fillStyle="#ffffff";sk.ctx.fillRect(0,0,cv.width,cv.height);sk.undo=[];if(!silent)loadRef();}
function refreshRefSelect(){var sel=$("refSelect");if(!sel)return;var cur=sel.value;var opts='<option value="">Vierge</option><option value="__flat__">Mon croquis paramétrique (guide)</option>';state.inspirations.filter(function(x){return x.img&&x.img.indexOf("data:")===0;}).forEach(function(x){opts+='<option value="'+x.id+'">Réf : '+esc((x.title||"image").slice(0,24))+'</option>';});sel.innerHTML=opts;if(cur)sel.value=cur;}
function loadRef(){var cv=$("sketchCanvas");if(!sk.ctx)return;sk.ctx.fillStyle="#ffffff";sk.ctx.fillRect(0,0,cv.width,cv.height);sk.undo=[];var v=$("refSelect").value;if(!v)return;if(v==="__flat__"){var svgStr='<svg xmlns="http://www.w3.org/2000/svg" width="'+cv.width+'" height="'+cv.height+'" viewBox="0 0 300 470">'+$("designSvg").innerHTML+'</svg>';var blob=new Blob([svgStr],{type:"image/svg+xml"});var url=URL.createObjectURL(blob);var img=new Image();img.onload=function(){sk.ctx.globalAlpha=0.28;sk.ctx.drawImage(img,0,0,cv.width,cv.height);sk.ctx.globalAlpha=1;URL.revokeObjectURL(url);};img.src=url;return;}var insp=state.inspirations.filter(function(x){return x.id==v;})[0];if(insp&&insp.img){var im=new Image();im.onload=function(){var r=Math.min(cv.width/im.width,cv.height/im.height);var w=im.width*r,h=im.height*r;sk.ctx.globalAlpha=0.3;sk.ctx.drawImage(im,(cv.width-w)/2,(cv.height-h)/2,w,h);sk.ctx.globalAlpha=1;};im.src=insp.img;}}
function saveSketch(){var cv=$("sketchCanvas");var data;try{data=cv.toDataURL("image/jpeg",0.8);}catch(e){toast("Réf externe : impossible d'enregistrer");return;}var obj={id:uid(),title:"Mon croquis",img:data,note:"",url:"",platform:"Croquis",tags:[]};state.inspirations.unshift(obj);if(!save()){state.inspirations.shift();toast("Mémoire pleine");return;}renderInspo();refreshRefSelect();toast("Croquis enregistré dans tes inspirations");}

/* ===== PATRONS ===== */
function setPatMode(m){document.querySelectorAll("#patMode button").forEach(function(n){n.classList.toggle("on",n.dataset.m===m);});$("patBiblio").style.display=m=="biblio"?"block":"none";$("patCreer").style.display=m=="creer"?"block":"none";}
document.querySelectorAll("#patMode button").forEach(function(b){b.addEventListener("click",function(){setPatMode(b.dataset.m);});});
function importPattern(){var url=$("ptUrl").value.trim();var st=$("ptStatus"),pv=$("ptPreview");pv.innerHTML="";if(!url){toast("Colle le lien du patron");return;}if(!/^https?:\/\//.test(url))url="https://"+url;st.innerHTML='<span class="spin"></span> Récupération du patron…';fetchHtml(url).then(function(html){var m=metaFrom(html);window._pendPat={img:m.img,url:url,title:m.title,desc:m.desc};st.innerHTML=m.img?"Patron trouvé — ajuste et enregistre.":"Pas d'image trouvée, le lien sera quand même gardé.";pv.innerHTML='<div class="card" style="display:flex;gap:14px;flex-wrap:wrap;align-items:flex-start;">'+(m.img?'<img src="'+esc(m.img)+'" style="width:130px;height:130px;object-fit:cover;border-radius:10px;border:1px solid var(--line);" onerror="this.style.display=\'none\'">':'')+'<div style="flex:1;min-width:200px;"><label class="fld">Nom du patron</label><input id="ppTitle" type="text" value="'+esc((m.title||"").slice(0,90))+'"><label class="fld" style="margin-top:8px;">Détails</label><input id="ppNote" type="text" value="'+esc((m.desc||"").slice(0,140))+'"><button class="btn" style="margin-top:12px;" onclick="savePattern()">Enregistrer dans la bibliothèque</button></div></div>';}).catch(function(){window._pendPat={img:"",url:url,title:"",desc:""};st.innerHTML="Récupération impossible — enregistre quand même le lien.";pv.innerHTML='<div class="card"><label class="fld">Nom du patron</label><input id="ppTitle" type="text"><button class="btn" style="margin-top:12px;" onclick="savePattern()">Enregistrer</button></div>';});}
function savePattern(){var p=window._pendPat||{};var title=($("ppTitle")||{}).value||"Patron";var note=($("ppNote")||{}).value||"";var d=detect(title+" "+note);state.patrons.unshift({id:uid(),title:title.trim()||"Patron",img:p.img||"",note:note.trim(),url:p.url||"",type:(d.garment[0]||"")});save();$("ptUrl").value="";$("ptStatus").innerHTML="";$("ptPreview").innerHTML="";window._pendPat=null;renderPatList();toast("Patron ajouté à ta bibliothèque");}
function delPattern(id){state.patrons=state.patrons.filter(function(p){return p.id!=id;});save();renderPatList();}
function patternReperToProjet(id){var p=state.patrons.filter(function(x){return x.id==id;})[0];if(!p)return;state.projets.unshift({id:uid(),name:p.title,piece:(p.type||"Patron"),diff:"Intermédiaire",stat:"envie",tissu:"",date:""});save();renderProjets();renderCarnetStats();toast("Ajouté au carnet");}
