var piece="jupe";
var PIECES={jupe:{title:"Jupe à taille élastique",fields:[{k:"waist",l:"Tour de taille (cm)",v:72,profil:"taille"},{k:"len",l:"Longueur (cm)",v:55},{k:"full",l:"Ampleur (×)",v:1.8,step:0.1,min:1.3,max:2.6}]},tote:{title:"Tote bag",fields:[{k:"w",l:"Largeur du sac (cm)",v:38},{k:"h",l:"Hauteur du sac (cm)",v:42},{k:"anse",l:"Longueur des anses (cm)",v:60}]},coussin:{title:"Housse de coussin",fields:[{k:"cote",l:"Côté du coussin (cm)",v:45},{k:"rabat",l:"Recouvrement dos (cm)",v:15}]},taie:{title:"Taie d'oreiller",fields:[{k:"larg",l:"Largeur oreiller (cm)",v:60},{k:"haut",l:"Hauteur oreiller (cm)",v:40}]},chouchou:{title:"Chouchou",fields:[{k:"larg",l:"Largeur du tissu plié (cm)",v:11},{k:"long",l:"Longueur (cm)",v:54}]},bandeau:{title:"Bandeau cheveux",fields:[{k:"tour",l:"Tour de tête (cm)",v:56},{k:"larg",l:"Largeur du bandeau (cm)",v:10}]}};
document.querySelectorAll("#pieceSeg button").forEach(function(b){b.addEventListener("click",function(){document.querySelectorAll("#pieceSeg button").forEach(function(n){n.classList.remove("on");});b.classList.add("on");piece=b.dataset.p;renderPatronControls();});});
["optSeam","optEase","optFw"].forEach(function(i){$(i).addEventListener("input",computePatron);});
function renderPatronControls(){var cfg=PIECES[piece];var prof=state.profil.mesures||{};var html='<h3 style="font-size:16px;margin-bottom:14px;">'+cfg.title+'</h3>';cfg.fields.forEach(function(f){var val=f.v;if(f.profil&&prof[f.profil])val=prof[f.profil];html+='<div style="margin-bottom:12px;"><label class="fld">'+f.l+(f.profil&&prof[f.profil]?' &middot; <span style="color:var(--accent)">depuis mon profil</span>':'')+'</label><input type="number" id="pf_'+f.k+'" value="'+val+'" step="'+(f.step||1)+'"'+(f.min?' min="'+f.min+'"':'')+(f.max?' max="'+f.max+'"':'')+'></div>';});$("patronControls").innerHTML=html;cfg.fields.forEach(function(f){$("pf_"+f.k).addEventListener("input",computePatron);});computePatron();}
function gvp(k){var e=$("pf_"+k);return e?parseFloat(e.value)||0:0;}
function computePatron(){var seam=parseFloat($("optSeam").value)||0,ease=parseFloat($("optEase").value)||0,fw=parseFloat($("optFw").value)||140;var kpi=[],cw,ch,res={};
  if(piece=="jupe"){var W=gvp("waist")+ease,L=gvp("len"),f=gvp("full");cw=Math.round((W*f)/2+seam*2);ch=Math.round(L+4+3);var metre=((cw*2<=fw)?ch:ch*2)/100;kpi=[["Largeur à couper",cw+" cm"],["Hauteur à couper",ch+" cm"],["Panneaux","2"],["Élastique",Math.round(gvp("waist")*0.92)+" cm"],["Tissu ("+fw+"cm)",metre.toFixed(2)+" m",true]];res={name:"Jupe élastique",tissu:metre.toFixed(2)+" m en "+fw+" cm"};drawRect(cw,ch,"gaine élastique","ourlet","à couper ×2");}
  else if(piece=="tote"){var w=gvp("w")+ease,h=gvp("h"),a=gvp("anse");cw=Math.round(w+seam*2);ch=Math.round(h*2+seam*2+6);var metreT=(ch+(a>0?12:0))/100;kpi=[["Largeur à couper",cw+" cm"],["Hauteur (pliée)",ch+" cm"],["Anses","2 × "+a+" cm"],["Tissu ("+fw+"cm)",metreT.toFixed(2)+" m",true]];res={name:"Tote bag",tissu:metreT.toFixed(2)+" m"};drawRect(cw,ch,"pli du fond","rabat haut","corps plié en 2");}
  else if(piece=="coussin"){var c=gvp("cote")+ease,r=gvp("rabat");cw=Math.round(c+seam*2);ch=Math.round(c*2+r+seam*2);var metreC=ch/100;kpi=[["Largeur à couper",cw+" cm"],["Hauteur (dos enveloppe)",ch+" cm"],["Type","dos portefeuille"],["Tissu ("+fw+"cm)",metreC.toFixed(2)+" m",true]];res={name:"Housse de coussin",tissu:metreC.toFixed(2)+" m"};drawRect(cw,ch,"rabat","rabat","dos qui se recouvre");}
  else if(piece=="taie"){var lg=gvp("larg")+ease,ht=gvp("haut");cw=Math.round(lg+seam*2);ch=Math.round(ht*2+seam*2+18);var metreP=ch/100;kpi=[["Largeur à couper",cw+" cm"],["Hauteur (avec rabat)",ch+" cm"],["Rabat","~ 15 cm"],["Tissu ("+fw+"cm)",metreP.toFixed(2)+" m",true]];res={name:"Taie d'oreiller",tissu:metreP.toFixed(2)+" m"};drawRect(cw,ch,"rabat intérieur","ourlet","taie portefeuille");}
  else if(piece=="bandeau"){var tt=gvp("tour"),lb=gvp("larg");cw=Math.round(tt*0.6+seam*2);ch=Math.round(lb*2+seam*2);var metreBa=ch/100;kpi=[["Largeur à couper",cw+" cm"],["Hauteur à couper",ch+" cm"],["Élastique dos","~ "+Math.round(tt*0.25)+" cm"],["Tissu",metreBa.toFixed(2)+" m",true]];res={name:"Bandeau",tissu:"chutes"};drawRect(cw,ch,"tube replié","couture","noeud ou élastique");}
  else {var lgc=gvp("larg"),loc=gvp("long");cw=Math.round(lgc*2+seam*2);ch=Math.round(loc+seam*2);var metreH=ch/100;kpi=[["Largeur à couper",cw+" cm"],["Longueur à couper",ch+" cm"],["Élastique","~ 18 cm"],["Tissu",metreH.toFixed(2)+" m",true]];res={name:"Chouchou",tissu:"chutes"};drawRect(cw,ch,"tube replié","passage élastique","tube de tissu");}
  window._patronRes=res;$("patronKpis").innerHTML=kpi.map(function(k){return '<div class="kpi'+(k[2]?' hl':'')+'"><div class="n">'+k[1]+'</div><div class="l">'+k[0]+'</div></div>';}).join("");}
function drawRect(cw,ch,topLbl,botLbl,centerLbl){var svg=$("patronSvg");var pad=46,availW=340-pad*1.4,availH=300-pad*1.3;var s=Math.min(availW/cw,availH/ch),w=cw*s,h=ch*s,x=(340-w)/2,y=(300-h)/2;var bandH=Math.min(h*0.18,26);svg.innerHTML='<rect x="'+x+'" y="'+y+'" width="'+w+'" height="'+h+'" fill="#f3e7ee"/><rect x="'+x+'" y="'+y+'" width="'+w+'" height="'+bandH+'" fill="#9c5d7c" fill-opacity="0.22"/><rect x="'+x+'" y="'+(y+h-bandH)+'" width="'+w+'" height="'+bandH+'" fill="#9c5d7c" fill-opacity="0.12"/><rect x="'+x+'" y="'+y+'" width="'+w+'" height="'+h+'" fill="none" stroke="#9c5d7c" stroke-width="1.5"/><line x1="'+x+'" y1="'+(y+bandH)+'" x2="'+(x+w)+'" y2="'+(y+bandH)+'" stroke="#9c5d7c" stroke-dasharray="4 3"/><line x1="'+x+'" y1="'+(y+h-bandH)+'" x2="'+(x+w)+'" y2="'+(y+h-bandH)+'" stroke="#9c5d7c" stroke-dasharray="4 3"/>'+tx(x+w/2,y+bandH/2+3,topLbl,9)+tx(x+w/2,y+h-bandH/2+3,botLbl,9)+tx(x+w/2,y+h/2+3,centerLbl,10)+tx(x+w/2,y+h+18,cw+" cm",11)+'<text x="'+(x-12)+'" y="'+(y+h/2)+'" transform="rotate(-90 '+(x-12)+' '+(y+h/2)+')" text-anchor="middle" font-size="11" fill="#8c8278" font-family="sans-serif">'+ch+' cm</text>';}
function tx(x,y,t,s){return '<text x="'+x+'" y="'+y+'" text-anchor="middle" font-size="'+s+'" fill="#6f3d56" font-family="sans-serif">'+t+'</text>';}
function patronToCarnet(){var r=window._patronRes;if(!r)return;state.projets.unshift({id:uid(),name:r.name+" (sur mesure)",piece:PIECES[piece].title,diff:"Facile",stat:"envie",tissu:r.tissu,date:""});save();renderProjets();renderCarnetStats();toast("Ajouté au carnet");}

