function setTissuMode(m){document.querySelectorAll("#tissuMode button").forEach(function(n){n.classList.toggle("on",n.dataset.m===m);});$("tissuMatieres").style.display=m=="matieres"?"block":"none";$("tissuVetement").style.display=m=="vetement"?"block":"none";$("tissuPiece").style.display=m=="piece"?"block":"none";}
document.querySelectorAll("#tissuMode button").forEach(function(b){b.addEventListener("click",function(){setTissuMode(b.dataset.m);});});
var GARM={robe_sm:{l:"Robe sans manche",extra:20,sleeve:0,two:false},robe_ml:{l:"Robe manches longues",extra:20,sleeve:55,two:false},jupe:{l:"Jupe",extra:12,sleeve:0,two:false},jupe_longue:{l:"Jupe longue",extra:14,sleeve:0,two:false},top_sm:{l:"Top sans manche",extra:12,sleeve:0,two:false},top_ml:{l:"Top/chemise manches longues",extra:14,sleeve:50,two:false},pantalon:{l:"Pantalon",extra:14,sleeve:0,two:true},short:{l:"Short",extra:12,sleeve:0,two:true},veste:{l:"Veste",extra:25,sleeve:55,two:false},manteau:{l:"Manteau",extra:30,sleeve:60,two:false}};
["gType","gCirc","gLen","gFw","gPrice"].forEach(function(i){$(i).addEventListener("input",computeGarment);});
function computeGarment(){var g=GARM[$("gType").value]||GARM.robe_sm;var circ=parseFloat($("gCirc").value)||0,len=parseFloat($("gLen").value)||0,fw=parseFloat($("gFw").value)||140,price=parseFloat($("gPrice").value)||0;var needWidth=circ*1.05;var lengths=(needWidth>fw||g.two)?2:1;var metre=(lengths*(len+g.extra)+g.sleeve)/100;metre=Math.ceil(metre*10)/10;var cost=metre*price;$("gKpis").innerHTML=gbox(metre.toFixed(1)+" m","Tissu à acheter",true)+gbox(cost.toFixed(2)+" €","Budget tissu",true)+gbox(lengths+(lengths>1?" longueurs":" longueur"),"Disposition")+gbox(Math.round(needWidth)+" cm","Largeur à plat requise");var note="Estimation pour une "+g.l.toLowerCase()+" en "+fw+" cm de large. ";if(lengths>1&&!g.two)note+="Plus large que le tissu : deux longueurs. ";if(g.two)note+="Coupé en deux longueurs (jambes). ";if(g.sleeve)note+="Marge manches incluse. ";note+="Vérifie toujours le tableau de métrage du patron.";$("gNote").textContent=note;}
function gbox(n,l,hl){return '<div class="kpi'+(hl?' hl':'')+'"><div class="n">'+n+'</div><div class="l">'+l+'</div></div>';}
function computeTissu(){var w=parseFloat($("tW").value)||0,h=parseFloat($("tH").value)||0,n=parseFloat($("tN").value)||0,fw=parseFloat($("tFw").value)||140,seam=parseFloat($("tSeam").value)||0,price=parseFloat($("tPrice").value)||0;var cw=w+seam*2,ch=h+seam*2;var perRow=Math.max(1,Math.floor(fw/cw));var rows=Math.ceil(n/perRow);var metre=(rows*ch)/100,cout=metre*price;$("tissuKpis").innerHTML=gbox(cw.toFixed(0)+" × "+ch.toFixed(0)+" cm","Pièce avec marges")+gbox(perRow+" / largeur","Pièces côte à côte")+gbox(metre.toFixed(2)+" m","Métrage",true)+gbox(cout.toFixed(2)+" €","Budget",true);}
["tW","tH","tN","tFw","tSeam","tPrice"].forEach(function(i){$(i).addEventListener("input",computeTissu);});

