$("fabUsage").addEventListener("change",renderFabrics);$("fabDrape").addEventListener("change",renderFabrics);
function renderFabrics(){var fu=$("fabUsage").value,fd=$("fabDrape").value;var list=FABRICS.filter(function(f){return (fu=="tous"||f.u.indexOf(fu)>=0)&&(fd=="tous"||f.d==fd);});var el=$("fabricList");if(!list.length){el.innerHTML='<div class="empty" style="grid-column:1/-1;">Aucune matière pour ce filtre.</div>';return;}el.innerHTML=list.map(function(f){return '<div class="fab"><div class="nm">'+esc(f.n)+'</div><div style="margin:6px 0;"><span class="tag lvl">'+esc(f.lv)+'</span> <span class="tag diff">tombé '+esc(f.d)+'</span></div><div class="muted" style="font-size:13px;line-height:1.5;">'+esc(f.de)+'</div><div style="font-size:12.5px;margin-top:8px;color:var(--accent-ink);">Poids '+esc(f.w)+' &middot; Stretch '+esc(f.s)+'</div><button class="btn ghost sm" style="margin-top:10px;" onclick="fabricToProjet('+"'"+jsq(f.n)+"'"+')">&#8594; carnet</button></div>';}).join("");}
function fabricToProjet(name){state.projets.unshift({id:uid(),name:"Projet en "+name,piece:"",diff:"Facile",stat:"envie",tissu:name,date:""});save();renderProjets();renderCarnetStats();toast("Idée tissu ajoutée au carnet");}

/* ===== CAPSULE ===== */
var CAT={haut:"Haut",bas:"Bas",robe:"Robe",veste:"Veste"};
function addCapsule(){var n=$("cName").value.trim();if(!n){toast("Nomme la pièce");return;}state.capsule.unshift({id:uid(),name:n,cat:$("cCat").value,color:$("cColor").value});save();$("cName").value="";renderCapsule();toast("Pièce ajoutée");}
function delCapsule(id){state.capsule=state.capsule.filter(function(c){return c.id!=id;});save();renderCapsule();}
function renderCapsule(){var c={haut:0,bas:0,robe:0,veste:0};state.capsule.forEach(function(p){c[p.cat]++;});var tenues=c.haut*c.bas+c.robe;$("capsuleStats").innerHTML=stat(state.capsule.length,"Pièces")+stat(tenues,"Tenues possibles")+stat(c.veste,"Vestes (à superposer)");var el=$("capsuleList");if(!state.capsule.length){el.innerHTML='<div class="empty" style="grid-column:1/-1;">Ajoute tes pièces pour voir combien de tenues tu peux composer.</div>';return;}el.innerHTML=state.capsule.map(function(p){return '<div class="card" style="display:flex;align-items:center;gap:12px;"><div class="swatch" style="background:'+esc(p.color)+';width:40px;height:40px;flex-shrink:0;"></div><div style="flex:1;"><div style="font-weight:600;">'+esc(p.name)+'</div><div class="muted" style="font-size:13px;">'+CAT[p.cat]+'</div></div><button class="x" onclick="delCapsule('+p.id+')">&times;</button></div>';}).join("");}

/* ===== PROFIL ===== */
var MES=[["mTaille","taille"],["mPoitrine","poitrine"],["mHanches","hanches"],["mGenou","genou"],["mDos","dos"],["mPoignet","poignet"]];
function fillProfil(){var m=state.profil.mesures||{};MES.forEach(function(p){if(m[p[1]]!=null)$(p[0]).value=m[p[1]];});renderStyleChips();}
function saveProfil(){var m={};MES.forEach(function(p){var v=$(p[0]).value;if(v!=="")m[p[1]]=parseFloat(v);});state.profil.mesures=m;save();renderPatronControls();toast("Profil enregistré");}
function addStyle(){var v=$("styleIn").value.trim();if(!v)return;state.profil.styles=state.profil.styles||[];state.profil.styles.push(v);$("styleIn").value="";save();renderStyleChips();}
function delStyle(i){state.profil.styles.splice(i,1);save();renderStyleChips();}
function renderStyleChips(){var el=$("styleChips");var s=state.profil.styles||[];el.innerHTML=s.length?s.map(function(t,i){return '<span class="chip">'+esc(t)+' <button class="x" style="font-size:14px;padding:0 2px;" onclick="delStyle('+i+')">&times;</button></span>';}).join(""):'<span class="muted" style="font-size:13px;">Aucun mot-clé pour l\'instant.</span>';}

/* ===== DATA ===== */
function exportData(){var blob=new Blob([JSON.stringify(state,null,2)],{type:"application/json"});var a=document.createElement("a");a.href=URL.createObjectURL(blob);a.download="mon-atelier-couture.json";a.click();URL.revokeObjectURL(a.href);toast("Sauvegarde exportée");}
function importData(file){if(!file)return;var rd=new FileReader();rd.onload=function(){try{var d=JSON.parse(rd.result);state=Object.assign(JSON.parse(JSON.stringify(DEFAULT)),d);save();renderAll();toast("Sauvegarde importée");}catch(e){toast("Fichier illisible");}};rd.readAsText(file);}

/* ===== SHARE + PWA ===== */
function handleShared(){var qs=new URLSearchParams(location.search);var shared=qs.get("url")||qs.get("text")||qs.get("shared")||"";var m=shared.match(/https?:\/\/[^\s]+/);if(m){goView("inspirations");$("impUrl").value=m[0];importLink();}}
if("serviceWorker" in navigator){try{navigator.serviceWorker.register("sw.js").catch(function(){});}catch(e){}}
(function(){var h=$("installHint");if(location.protocol==="file:")h.textContent="Tu ouvres l'app en local : le bouton Partager natif s'activera une fois l'app hébergée et installée.";else h.textContent="App en ligne — installe-la (menu → Installer l'application) pour la voir dans le menu Partager.";})();

